 export default class FetchBodyUtility {
+	/**
+	 * Creates a promise that rejects when a body read is interrupted by page teardown.
+	 *
+	 * @param window Window.
+	 * @returns Abort promise and abort handler.
+	 */
+	public static createAbortPromise(window: BrowserWindow): {
+		promise: Promise<never>;
+		abort: () => void;
+	} {
+		let reject: (reason: DOMException) => void;
+		const promise = new Promise<never>((_, rejectPromise) => {
+			reject = rejectPromise;
+		});
+
+		return {
+			promise,
+			abort: () =>
+				reject(
+					new window.DOMException(
+						'Failed to read response body: The stream was aborted.',
+						DOMExceptionNameEnum.abortError
+					)
+				)
+		};
+	}
+
